protected override void OnModelCreating(ModelBuilder modelBuilder)
{
    // Preserve "Discriminator" property name used by existing documents (EF Core 9 defaults to "$type")
    modelBuilder.Entity<Blog>().HasDiscriminator<string>("Discriminator");
    // Preserve "Blog|1" id format used by existing documents (EF Core 9 defaults to key-only)
    modelBuilder.Entity<Blog>().HasRootDiscriminatorInJsonId(true);
    // HasIndex removed — Cosmos DB does not support EF-managed indexes (now throws at startup)
}

